class Union_Find {

public:

	VI node;

	void set(int n) {

		node.resize(n);

		REP(i, n) node[i] = i;

	}



	int root(int n) {

		if (node[n] == n) return n;

		else return node[n] = root(node[n]);

	}



	void unite(int n, int m) {

		if (n > m) swap(n, m);

